function sendForm(e,n,c){let t=$("#form_"+e).parent().parent().parent();if(t.find("input[name='personal']").is(":checked"))t.find("input#submit_"+e).trigger("click");else{document.querySelector("#personal_checked"+c).classList.contains("conf_unchecked")||$("#personal_checked"+c).toggleClass("conf_unchecked")}}
